solution_code:
#include <iostream>

int accumulate(int running, int next)
{
    return running + next;
}

int main()
{
    int x = 0;
    int y = 0;
    int z = 0;
    std::cin >> x >> y >> z;

    int total = 0;
    total = accumulate(total, x);
    std::cout << "after x: " << total << '\n';
    total = accumulate(total, y);
    std::cout << "after y: " << total << '\n';
    total = accumulate(total, z);
    std::cout << "after z: " << total << '\n';

    return 0;
}
